from collections.abc import Awaitable, Callable
import asyncio


async def run_tasks(
    tasks: list[Callable[[], Awaitable[None]]], max_concurrent: int
) -> None:
    """Run tasks with a bounded number of workers.

    A worker only calls the next callable after the previous callable has
    finished.  This means callables that are still queued do not have a
    coroutine running that could be started during cancellation.
    """
    if max_concurrent <= 0:
        raise ValueError("max_concurrent must be positive")
    if not tasks:
        return

    task_iter = iter(tasks)

    async def worker() -> None:
        while True:
            try:
                task = next(task_iter)
            except StopIteration:
                return
            await task()

    workers = [
        asyncio.create_task(worker())
        for _ in range(min(max_concurrent, len(tasks)))
    ]

    try:
        await asyncio.gather(*workers)
    except BaseException:
        # gather cancels children when it is itself cancelled, but doing this
        # explicitly also handles failures raised by an individual worker.
        for worker_task in workers:
            worker_task.cancel()
        await asyncio.gather(*workers, return_exceptions=True)
        raise
